        entries = _parse_partial_edits(raw)
        assert entries[0] == {"filepath": "a.py", "search": "old", "replace": "new"}
        # Trailing partial entry: filepath extracted, prefix stripped.
        assert entries[1].get("filepath") == "b.py"


